INSERT INTO prescription_examples (student_key, student_profile, workouts, workout_split) VALUES ('allan_gorski', '{"name":"Allan Mesquita Gorski","mapped_name":"allan_gorski","birth_date":"1995-05-08","profession":null,"sports_history":"Já realizei alguns anos de natação, gostei muito, sem pontos negativos. Futebol jogo desde que me conheço, porém com várias lesões (clavícula, ligamento medial e talofibular dos 2 tornozelos, porém sem nenhum incômodo para continuar praticando). E musculação na academia, ponto negativo é meu mesmo, falta de consistência e foco.","injuries":["Clavícula esquerda","lesão no osso","mas 100% recuperado","sem dores. Ligamentos tornozelo (medial e talofibular) 100% recuperado","sem dores."],"health_conditions":["Nada a declarar."],"medications":["Não."],"current_practice":"A 18 anos.","goal":"Me tornei pai recentemente, e meu maior objetivo é estar mais saudável para poder acompanhar e criar meu filho. Em paralelo acredito que a autoestima e também a performance no esporte (várzea/amador/casual) sejam razões paralelas ao objetivo principal.","weekly_frequency":3,"session_duration":"De 40 min a 1h20.","gender":"M","experience_level":"intermediário","form_timestamp":"2025/04/25 9:06:35 AM GMT-3"}'::jsonb, '{"A":{"focus":null,"exercises":[{"name":"Puxada Frente Pegada Supinada","method":"Tradicional","series":{"serie_1":{"interval":"1''30"}}},{"name":"Remada Máquina Pegada Neutra","method":"Tradicional","series":{"serie_1":{"interval":"1''30"}}},{"name":"Agachamento Smith","method":"Tradicional","series":{"serie_1":{"interval":"1''30\" - 2''"}}},{"name":"Avanço com Halteres","method":"Tradicional","series":{"serie_1":{"interval":"1''","obs":"X"},"serie_4":{"reps":"X"}}},{"name":"Cadeira Extensora","method":"Tradicional","series":{"serie_1":{"reps":"10-14","interval":"1''"}}},{"name":"Preventivo: \n3x 10 / 10  Aviãozinho\n20 Elevações Tibial Anterior\n30 Toques no Ombro alt.","method":"Tradicional","series":{}}]},"B":{"focus":null,"exercises":[{"name":"Supino Reto Máquina","method":"Tradicional","series":{"serie_1":{"interval":"1''30","obs":"X"}}},{"name":"Desenvolvimento de Ombros Halter","method":"Tradicional","series":{"serie_1":{"weight":"Aprox. 10-12kg cada halter","interval":"1''30\""},"serie_4":{"reps":"X"}}},{"name":"Levantamento Terra Barra","method":"Tradicional","series":{"serie_1":{"interval":"1''30\""}}},{"name":"Cadeira Flexora","method":"Tradicional","series":{"serie_1":{"reps":"10-14","interval":"1''","obs":"X"},"serie_4":{"reps":"X"}}},{"name":"Tríceps Barra Polia Alta","method":"Tradicional","series":{"serie_1":{"reps":"10-14","interval":"1''","obs":"X"},"serie_4":{"reps":"X"}}},{"name":"Preventivo: \n10 / 10 Elevação Pélvica Unilateral\n30\"/30\" Prancha Lateral","method":"Tradicional","series":{}}]}}'::jsonb, ARRAY['A','B']::TEXT[]) ON CONFLICT (student_key) DO UPDATE SET student_profile = EXCLUDED.student_profile, workouts = EXCLUDED.workouts, workout_split = EXCLUDED.workout_split;